import numpy as np


class Slicer:
    def __init__(self, cols=5):
        self.cols = cols

    def slice_2d(self, arr):
        # BUG: assumes 2D but arr is 1D
        return arr[0, :self.cols]

    def reshape_first(self, arr, rows):
        return arr.reshape(rows, -1)


def slice_2d(arr):
    return Slicer().slice_2d(arr)


def main():
    arr = np.arange(20)
    r = slice_2d(arr)
    print(r)


if __name__ == '__main__':
    main()
